<template>
	<div>
		<div id="background"></div>
		<el-form ref="form" label-width="80px" inline="true" class="login_container" :model="form" :rules="rules">
			<h3 class="login_title">用户注册</h3>
			<el-form-item label="用户名" prop="username">
				<el-input v-model="form.username" placeholder="请输入用户名"></el-input>
			</el-form-item>
			<el-form-item label="姓名" prop="name">
				<el-input v-model="form.name" placeholder="请输入姓名"></el-input>
			</el-form-item>
			<el-form-item label="密码" prop="password">
				<el-input type="password" v-model="form.password" placeholder="请输入密码"></el-input>
			</el-form-item>
			<el-form-item label="确认密码" prop="confirmPassword">
				<el-input type="password" v-model="form.confirmPassword" placeholder="请确认密码"></el-input>
			</el-form-item>
			<el-form-item label="手机号" prop="phone">
				<el-input class="phone" v-model="form.phone" placeholder="请输入手机号"></el-input>
			</el-form-item>
			<el-form-item>
				<el-button @click="onClickSendCaptcha" :disabled="sendButtonDisabled">{{sendButtonMsg}}</el-button>
			</el-form-item>
			<el-form-item label="验证码" prop="captcha">
				<el-input class="password" type="captcha" v-model="form.captcha" placeholder="请输入验证码"></el-input>
			</el-form-item>
			<el-form-item>
				<el-button style="margin-left: 192px;" type="text" @click="onClickReturn">返回登录
				</el-button>
			</el-form-item>
			<el-form-item>
				<el-button style="" type="success" @click="onClickRegister">注册</el-button>
			</el-form-item>
		</el-form>
	</div>
</template>

<script>
	export default {
		data() {
			return {
				sendButtonDisabled: false,
				sendButtonMsg: '发送验证码',
				form: {
					username: '',
					name: '',
					password: '',
					phone: '',
					confirmPassword: '',
				},

				rules: {
					name: [{
						required: true,
						trigger: 'blur',
						message: '请输入姓名'
					}],
					username: [{
						required: true,
						trigger: 'blur',
						message: '请输入用户名'

					}],
					password: [{
						required: true,
						trigger: 'blur',
						message: '请输入密码'

					}],
					confirmPassword: [{
						required: true,
						trigger: 'blur',
						message: '请确认密码'
					}],
					phone: [{
							required: true,
							trigger: 'blur',
							message: '请输入手机号'
						},
						{
							pattern: /^1(3|4|5|6|7|8)\d{9}$/,
							message: '请输入正确的手机号'
						}
					],
					captcha: [{
						required: true,
						trigger: 'blur',
						message: '请输入验证码'
					}]
				}
			}
		},
		methods: {
			onClickSendCaptcha() {
				this.$axios.get(this.common.backendURL + '/api/manager/sendCaptcha?phone=' + this.form.phone).then(res => {
					if (res.data.code == 1) {
						this.sendButtonDisabled = true
						this.sendButtonMsg = '1分钟后重试'
						this.common.setTime(() => {
							this.sendButtonDisabled = false;
							this.sendButtonMsg = '发送验证码';
						}, 60000)
					} else {
						this.$message.error(res.data.msg);
					}
				})
			},
			onClickRegister() {
				this.$refs.form.validate(valid => {
					if (valid) {
						if (this.form.password !== this.form.confirmPassword) {
							this.$message.error('两次密码输入不一致')
							return
						}
						this.$axios.get(this.common.backendURL + '/api/user/checkCaptcha' + '?phone=' + this.form
							.phone + '&captcha=' + this.form
							.captcha + '&register=true').then(res => {
							if (res.data.code == 1) {
								this.$axios.post(this.common.backendURL + '/api/user/saveOne', this.form)
									.then(res => {
										if (res.data.code == 1) {
											this.$message.success('注册成功')
											this.$router.push('/')
										} else {
											this.$message.error(res.data.msg)
										}
									})
							} else {
								this.$message.error(res.data.msg)
							}
						})
					}
				})
			},
			onClickReturn() {
				this.$router.push('/')
			}
		}
	}
</script>

<style scoped>
	#background {
		background-image: url("../assets/img_login/bg.jpg");
		min-width: 1024px;
		position: fixed;
		top: 0;
		left: 0;
		height: 100%;
		width: 100%;
		background-position: center 0;
		background-repeat: no-repeat;
		background-size: cover;
		z-index: -10;
	}

	.login_container {
		width: 425px;
		border: 1px solid #eaeaea;
		margin: 93px auto 0 auto;
		padding: 35px 35px 15px 35px;
		border-radius: 15px;
		background-color: #fff;
		box-shadow: 0 0 25px #cac6c6;
		box-sizing: border-box;
	}

	.login_container .el-input {
		width: 250px;
	}

	.login_container .phone {
		width: 130px;
	}

	.login_title {
		text-align: center;
		margin-bottom: 40px;
		color: #505458;
	}
</style>
